import React, { useEffect, useState, useCallback } from "react";
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Legend,
} from "recharts";
import Navbar from "../components/Navbar";
import axiosClient from "../api/axiosClient";
import { useAuth } from "../context/AuthContext";

const TIPS = [
  "Fix dripping taps — a single drip per second wastes over 11,000 litres a year.",
  "Take shorter showers; a 5-minute shower uses about half the water of a bath.",
  "Run washing machines and dishwashers only with full loads.",
  "Reuse RO reject water for mopping or watering plants.",
  "Install aerators on taps to cut flow without losing pressure.",
];

export default function ResidentDashboard() {
  const { user } = useAuth();
  const householdId = user?.householdId;

  const [usage, setUsage] = useState([]);
  const [invoices, setInvoices] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [peer, setPeer] = useState(null);
  const [readingDate, setReadingDate] = useState("");
  const [readingValue, setReadingValue] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const loadAll = useCallback(async () => {
    if (!householdId) return;
    try {
      const [usageRes, invoiceRes, alertRes, peerRes] = await Promise.all([
        axiosClient.get(`/resident/households/${householdId}/usage-logs`),
        axiosClient.get(`/resident/households/${householdId}/invoices`),
        axiosClient.get(`/resident/households/${householdId}/alerts`),
        axiosClient.get(`/resident/households/${householdId}/peer-comparison`),
      ]);
      setUsage(usageRes.data);
      setInvoices(invoiceRes.data);
      setAlerts(alertRes.data);
      setPeer(peerRes.data);
    } catch (e) {
      // ignore - dashboard renders with whatever loaded
    }
  }, [householdId]);

  useEffect(() => { loadAll(); }, [loadAll]);

  const chartData = usage.map((u) => ({
    date: u.readingDate,
    consumption: Number(u.consumptionKl || 0),
  }));

  const handleLogReading = async (e) => {
    e.preventDefault();
    setError(""); setMessage("");
    try {
      await axiosClient.post("/resident/usage-logs", {
        householdId, readingDate, readingValue: Number(readingValue),
      });
      setMessage("Reading logged successfully.");
      setReadingDate(""); setReadingValue("");
      loadAll();
    } catch (err) {
      setError(err.response?.data?.message || "Could not log reading.");
    }
  };

  const peerChartData = peer ? [
    { label: "You", value: peer.myConsumptionKl },
    { label: "Apartment Avg", value: peer.apartmentAverageKl },
    { label: "Similar-sized Avg", value: peer.similarSizedAverageKl },
  ] : [];

  return (
    <div>
      <Navbar />
      <div className="container" style={{ paddingTop: 32, paddingBottom: 48 }}>
        <h1 className="page-title">Welcome back, {user?.fullName}</h1>
        <p className="page-subtitle">Your household's water consumption, billing, and alerts.</p>

        <div className="grid grid-3" style={{ marginBottom: 24 }}>
          <div className="card stat-card">
            <div className="stat-value">{chartData.length ? chartData[chartData.length - 1].consumption.toFixed(2) : "0.00"} kL</div>
            <div className="stat-label">Latest reading consumption</div>
          </div>
          <div className="card stat-card">
            <div className="stat-value">{invoices.length ? `Rs. ${invoices[0].total}` : "—"}</div>
            <div className="stat-label">Most recent bill</div>
          </div>
          <div className="card stat-card">
            <div className="stat-value">{alerts.filter(a => !a.resolved).length}</div>
            <div className="stat-label">Active alerts</div>
          </div>
        </div>

        {alerts.filter(a => !a.resolved).length > 0 && (
          <div className="alert-banner">
            {alerts.filter(a => !a.resolved).slice(0, 3).map((a) => (
              <div key={a.id} style={{ marginBottom: 4 }}>⚠ {a.message}</div>
            ))}
          </div>
        )}

        <div className="grid grid-2" style={{ marginBottom: 24 }}>
          <div className="card">
            <h3 style={{ marginBottom: 16 }}>Daily Consumption Trend</h3>
            <ResponsiveContainer width="100%" height={260}>
              <LineChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
                <XAxis dataKey="date" fontSize={11} />
                <YAxis fontSize={11} label={{ value: "kL", angle: -90, position: "insideLeft", fontSize: 11 }} />
                <Tooltip />
                <Line type="monotone" dataKey="consumption" stroke="#0e7490" strokeWidth={2} dot={false} />
              </LineChart>
            </ResponsiveContainer>
          </div>

          <div className="card">
            <h3 style={{ marginBottom: 16 }}>You vs. Your Peers</h3>
            {peer ? (
              <ResponsiveContainer width="100%" height={260}>
                <BarChart data={peerChartData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
                  <XAxis dataKey="label" fontSize={11} />
                  <YAxis fontSize={11} />
                  <Tooltip />
                  <Bar dataKey="value" fill="#22d3ee" radius={[6, 6, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            ) : <p style={{ color: "#64748b", fontSize: 13 }}>Not enough data yet.</p>}
          </div>
        </div>

        <div className="grid grid-2" style={{ marginBottom: 24 }}>
          <div className="card">
            <h3 style={{ marginBottom: 16 }}>Log Today's Meter Reading</h3>
            {message && <div className="success-banner">{message}</div>}
            {error && <div className="alert-banner">{error}</div>}
            <form onSubmit={handleLogReading}>
              <div className="form-group">
                <label>Reading Date</label>
                <input type="date" value={readingDate} onChange={(e) => setReadingDate(e.target.value)} required />
              </div>
              <div className="form-group">
                <label>Meter Reading Value (cumulative, kL)</label>
                <input type="number" step="0.001" value={readingValue} onChange={(e) => setReadingValue(e.target.value)} required />
              </div>
              <button className="btn btn-primary btn-block">Submit Reading</button>
            </form>
          </div>

          <div className="card">
            <h3 style={{ marginBottom: 16 }}>Water-Saving Tips</h3>
            <ul style={{ paddingLeft: 18, fontSize: 14, color: "#334155", lineHeight: 2 }}>
              {TIPS.map((t, i) => <li key={i}>{t}</li>)}
            </ul>
          </div>
        </div>

        <div className="card">
          <h3 style={{ marginBottom: 16 }}>Invoice History</h3>
          {invoices.length === 0 ? (
            <p style={{ color: "#64748b", fontSize: 14 }}>No invoices yet — they'll appear here once your admin finalizes a billing cycle.</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Date</th><th>Consumption (kL)</th><th>Base Charge</th><th>Shared Allocation</th><th>Total</th><th></th>
                </tr>
              </thead>
              <tbody>
                {invoices.map((inv) => (
                  <tr key={inv.id}>
                    <td>{new Date(inv.createdAt).toLocaleDateString()}</td>
                    <td>{inv.consumptionKl}</td>
                    <td>Rs. {inv.baseCharge}</td>
                    <td>Rs. {inv.sharedAllocation}</td>
                    <td><strong>Rs. {inv.total}</strong></td>
                    <td>
                      <a
                        className="btn btn-outline btn-sm"
                        href={`${axiosClient.defaults.baseURL}/resident/invoices/${inv.id}/pdf`}
                        target="_blank" rel="noreferrer"
                        onClick={(e) => {
                          e.preventDefault();
                          axiosClient.get(`/resident/invoices/${inv.id}/pdf`, { responseType: "blob" })
                            .then((res) => {
                              const url = window.URL.createObjectURL(new Blob([res.data], { type: "application/pdf" }));
                              const link = document.createElement("a");
                              link.href = url;
                              link.setAttribute("download", `invoice-${inv.id}.pdf`);
                              document.body.appendChild(link);
                              link.click();
                              link.remove();
                            });
                        }}
                      >
                        Download PDF
                      </a>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}
